import json
import re

# Step 1: Read all NPM packages and find latest release versions
package_file = locals()['var_functions.query_db:12']
with open(package_file, 'r') as f:
    all_packages = json.load(f)

# Find latest release version for each NPM package
latest_packages = {}
for pkg in all_packages:
    try:
        version_info = json.loads(pkg['VersionInfo'])
        name = pkg['Name']
        version = pkg['Version']
        ordinal = version_info.get('Ordinal', 0)
        is_release = version_info.get('IsRelease', False)

        if is_release:
            if name not in latest_packages or ordinal > latest_packages[name]['ordinal']:
                latest_packages[name] = {
                    'name': name,
                    'version': version,
                    'ordinal': ordinal
                }
    except:
        continue

# Step 2: Read project_packageversion mappings
ppv_file = locals()['var_functions.query_db:18']
with open(ppv_file, 'r') as f:
    project_mappings = json.load(f)

# Create lookup: (name, version) -> project_name
project_lookup = {}
for mapping in project_mappings:
    key = (mapping['Name'], mapping['Version'])
    project_lookup[key] = mapping['ProjectName']

# Find project mappings for our latest packages
packages_with_projects = []
for pkg_name, pkg_info in latest_packages.items():
    key = (pkg_name, pkg_info['version'])
    if key in project_lookup:
        packages_with_projects.append({
            'name': pkg_name,
            'version': pkg_info['version'],
            'project_name': project_lookup[key]
        })

# Step 3: Read project_info and extract star counts
proj_info_file = locals()['var_functions.query_db:26']
with open(proj_info_file, 'r') as f:
    project_info_list = json.load(f)

# Create lookup: project_name -> star count
star_lookup = {}
for proj in project_info_list:
    info_text = proj['Project_Information']
    # Extract project name and star count from text like: "The project leaflet/leaflet on GitHub ... has 38715 stars"
    match = re.search(r'The project\s+([\w\-]+/[\w\-]+)\s+.*?\b(\d+)\s+stars?', info_text)
    if match:
        project_name = match.group(1)
        stars = int(match.group(2))
        star_lookup[project_name] = stars

# Step 4: Combine everything and get top 5 packages by star count
final_packages = []
for pkg in packages_with_projects:
    project_name = pkg['project_name']
    if project_name in star_lookup:
        final_packages.append({
            'name': pkg['name'],
            'version': pkg['version'],
            'project_name': project_name,
            'stars': star_lookup[project_name]
        })

# Sort by star count desc and get top 5
top_5_packages = sorted(final_packages, key=lambda x: x['stars'], reverse=True)[:5]

print('__RESULT__:')
print(json.dumps({
    'total_latest_packages': len(latest_packages),
    'packages_with_stars': len(final_packages),
    'top_5_packages': top_5_packages
}, default=str))

